/**
 * @name Path traversal - cleanPath with protocol prefix injection
 * @description StringUtils.cleanPath() strips protocol prefixes (like 'file:') before cleaning.
 *              If user input contains 'file:../../../etc/passwd', cleanPath treats 'file:' as a protocol 
 *              prefix and resolves the path relative to filesystem, bypassing classpath containment.
 * @kind problem
 * @problem.severity error
 * @id java/cleanpath-protocol-prefix-injection
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

// Find the cleanPath method in StringUtils
class CleanPathMethod extends Method {
  CleanPathMethod() {
    this.hasName("cleanPath") and
    this.getDeclaringType().hasQualifiedName("spark.utils", "StringUtils")
  }
}

// Find StringUtils.cleanPath calls that receive user input
class CleanPathCall extends MethodCall {
  CleanPathCall() {
    this.getMethod() instanceof CleanPathMethod
  }
}

// Find where cleanPath result is used in ClassPathResource or ExternalResource constructors
// specifically where the path goes from user-controlled to cleanPath then to ClassLoader.getResource
from CleanPathCall cleanPathCall, MethodCall getResourceCall
where
  getResourceCall.getMethod().hasName("getResource") and
  (
    getResourceCall.getMethod().getDeclaringType().hasQualifiedName("java.lang", "ClassLoader") or
    getResourceCall.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class")
  ) and
  TaintTracking::localTaint(
    DataFlow::exprNode(cleanPathCall),
    DataFlow::exprNode(getResourceCall.getAnArgument())
  )
select cleanPathCall, 
  "cleanPath() output flows to ClassLoader.getResource() - protocol prefix injection (e.g., 'file:../../../etc/passwd') may bypass classpath containment"

/**
 * @name Path traversal via HTTP request to static file serving
 * @description Taint flow from HTTP request URI to file system operations in resource handlers
 * @kind path-problem
 * @problem.severity error
 * @id java/path-traversal-http-to-fs
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // HTTP request URI/path sources
    exists(MethodCall mc |
      mc.getMethod().hasName("getRequestURI") or
      mc.getMethod().hasName("getPathInfo") or
      mc.getMethod().hasName("getServletPath") or
      mc.getMethod().hasName("getParameter") |
      source.asExpr() = mc
    )
    or
    // AbstractResourceHandler receives path from request
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasQualifiedName("spark.resource", "AbstractResourceHandler") and
      p.getCallable().hasName("getResource") |
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") |
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ClassLoader.getResource / getResourceAsStream
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") |
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: HTTP input flows to file system sink $@.", source.getNode(), "source"

/**
 * @name StringUtils cleanPath protocol prefix bypass analysis
 * @description Find calls to StringUtils.cleanPath where the result is used for path containment checking, 
 *              potentially allowing bypass via protocol prefixes like file: or classpath:
 * @kind problem
 * @problem.severity error
 * @id java/cleanpath-protocol-prefix-bypass
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.DataFlow
import semmle.code.java.dataflow.TaintTracking

// Find the cleanPath method
class CleanPathMethod extends Method {
  CleanPathMethod() {
    this.hasName("cleanPath") and
    this.getDeclaringType().hasQualifiedName("spark.utils", "StringUtils")
  }
}

// Find the applyRelativePath method that processes path concatenation
class ApplyRelativePathMethod extends Method {
  ApplyRelativePathMethod() {
    this.hasName("applyRelativePath") and
    this.getDeclaringType().hasQualifiedName("spark.utils", "StringUtils")
  }
}

from MethodCall mc, CleanPathMethod cleanPath
where
  mc.getMethod() = cleanPath
select mc, "Call to StringUtils.cleanPath() at line " + mc.getLocation().getStartLine() + " in " + mc.getEnclosingCallable().getDeclaringType().getName() + "." + mc.getEnclosingCallable().getName() + ". This method strips protocol prefixes (splitting on ':') which can alter path resolution."
